1	type Quote = { premium: number };
2	type Item = { type: string; cursed?: boolean; enchantment?: number };
3	type QuoteInput = {
4	  customer?: { yearsWithMHPCO: number };
5	  firstInsurance?: boolean;
6	  followUp?: boolean;
7	  items: Item[];
8	};
9	
10	const PROCESSING_FEE = 5;
11	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
12	  sword: 100,
13	  staff: 80,
14	  amulet: 60,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	const ALIKE_BLOCK_SIZE = 3;
20	const ALIKE_BLOCK_PREMIUM = 60;
21	const CURSE_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
24	const LOYALTY_YEARS_THRESHOLD = 2;
25	const LOYALTY_DISCOUNT_RATE = 0.2;
26	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
27	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
28	
29	const basePremiumFor = (item: Item): number => {
30	  if (!(item.type in BASE_PREMIUM_BY_TYPE)) {
31	    throw new Error(`Unknown item type: ${item.type}`);
32	  }
33	  return BASE_PREMIUM_BY_TYPE[item.type];
34	};
35	
36	const curseSurchargeRateFor = (item: Item): number =>
37	  item.cursed ? CURSE_SURCHARGE_RATE : 0;
38	
39	const enchantmentSurchargeRateFor = (item: Item): number =>
40	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
41	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE
42	    : 0;
43	
44	const totalSurchargeRateFor = (item: Item): number =>
45	  curseSurchargeRateFor(item) + enchantmentSurchargeRateFor(item);
46	
47	const itemPremiumFor = (item: Item): number =>
48	  basePremiumFor(item) * (1 + totalSurchargeRateFor(item));
49	
50	const sumItemPremiums = (items: Item[]): number =>
51	  items.reduce((sum, item) => sum + itemPremiumFor(item), 0);
52	
53	const isAlikeBlock = (items: Item[]): boolean =>
54	  items.length === ALIKE_BLOCK_SIZE &&
55	  items.every((item) => item.type === items[0].type);
56	
57	const componentsPremium = (items: Item[]): number =>
58	  isAlikeBlock(items) ? ALIKE_BLOCK_PREMIUM : sumItemPremiums(items);
59	
60	const loyaltyDiscountRateFor = (input: QuoteInput): number =>
61	  (input.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD
62	    ? LOYALTY_DISCOUNT_RATE
63	    : 0;
64	
65	const firstInsuranceSurchargeRateFor = (input: QuoteInput): number =>
66	  input.firstInsurance ? FIRST_INSURANCE_SURCHARGE_RATE : 0;
67	
68	const followUpDiscountRateFor = (input: QuoteInput): number =>
69	  input.followUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
70	
71	const policyAdjustmentRateFor = (input: QuoteInput): number =>
72	  firstInsuranceSurchargeRateFor(input) -
73	  loyaltyDiscountRateFor(input) -
74	  followUpDiscountRateFor(input);
75	
76	export const quote = (input: QuoteInput): Quote => {
77	  const componentsTotal = componentsPremium(input.items);
78	  const policyTotal = componentsTotal + componentsTotal * policyAdjustmentRateFor(input);
79	  return { premium: Math.ceil(policyTotal + PROCESSING_FEE) };
80	};
81	
82	export const claim = (_input: unknown): unknown => undefined;
